sql:
SELECT COUNT(show_id) AS number_of_shows
FROM shows
WHERE production_company_id = 1;

SELECT title
FROM shows
WHERE show_id = 1;

SELECT show_id, MAX(viewers_millions) AS max_viewership
FROM viewership
GROUP BY show_id;

SELECT show_id, viewers_millions
FROM viewership
ORDER BY viewers_millions DESC;

SELECT AVG(viewers_millions) AS average_viewership
FROM viewership
WHERE show_id = 1 AND air_date BETWEEN '2020-01-01' AND '2020-12-31';

SELECT COUNT(episode_id) AS total_episodes
FROM episodes
WHERE show_id = (SELECT show_id FROM shows WHERE title = 'The Sopranos');

external_knowledge:
- "ships" metaphorically refers to the shows;
- "set sail" metaphorically means the original air date;
- "winds" metaphorically stands for the genre, indicating the type of show;
- "harbors" metaphorically represents the production companies, which are the origins of the shows;
- "voyages" metaphorically indicates the total episodes.

sql:
SELECT AVG(viewers_millions) AS average_viewership_in_millions
FROM viewership
WHERE show_id = 1;

external_knowledge:
- 'the ships' are the shows;
- 'the companies that built them' are the production companies;
- 'the depth of their sailors' connection' refers to the average number of viewers per show;
- 'navigation strategies' are the marketing strategies;
- 'depth of the oceans they explored' represents the estimated impact on viewership;
- 'cost of their voyages' is the marketing budget;
- 'the bounty they returned with' is the ROI.
